import { Router } from 'express';
import { authenticate } from '../middleware/auth.js';
import { roleGuard } from '../middleware/roleGuard.js';
import { getTodaySummary, listCashouts, upsertCashout } from '../controllers/cashout.controller.js';
const router = Router();
const ownerOnly = [authenticate, roleGuard(['owner'])];
router.get('/today-summary', ownerOnly, getTodaySummary);
router.get('/', ownerOnly, listCashouts);
router.post('/', ownerOnly, upsertCashout);
export default router;
